"use client";

import { useState, useEffect } from "react";
import { useAppStore } from "@/lib/store";
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Wallet, Gamepad2, ArrowUpDown, CreditCard } from "lucide-react";
import Link from "next/link";
import { Spinner } from "@/components/ui/spinner";
import {
  Umbrella,
  Egg,
  Coins,
  Star,
  Heart,
  Diamond,
  Spade,
  Club,
  Trophy,
  Gem,
  Fish,
} from "lucide-react";
import { betApi, predictionApi } from "@/lib/api";
import { authApi } from "@/lib/api";

const ICONS = [
  { id: "umbrella", name: "Umbrella", Icon: Umbrella, color: "text-blue-500" },
  { id: "fish", name: "Fish", Icon: Fish, color: "text-yellow-500" },
  { id: "hen", name: "Hen", Icon: Egg, color: "text-orange-500" },
  { id: "coin", name: "Coin", Icon: Coins, color: "text-amber-500" },
  { id: "star", name: "Star", Icon: Star, color: "text-yellow-400" },
  { id: "heart", name: "Heart", Icon: Heart, color: "text-red-500" },
  { id: "diamond", name: "Diamond", Icon: Diamond, color: "text-cyan-500" },
  { id: "spade", name: "Spade", Icon: Spade, color: "text-slate-700" },
  { id: "club", name: "Club", Icon: Club, color: "text-green-600" },
  { id: "trophy", name: "Trophy", Icon: Trophy, color: "text-yellow-600" },
  { id: "gem", name: "Gem", Icon: Gem, color: "text-pink-500" },
];

export default function DashboardPage() {
  const { user } = useAppStore();
  const [currentSlot, setCurrentSlot] = useState<any>(null);
  const [selectedIcon, setSelectedIcon] = useState<string>("");
  const [betAmount, setBetAmount] = useState<string>("50");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [betsByIcon, setBetsByIcon] = useState<
    Record<string, { totalBets: number; totalAmount: number }>
  >({});
  const [timeRemaining, setTimeRemaining] = useState<string>("");
  const [slotLoading, setSlotLoading] = useState(true);
  const [hasBetCurrentSlot, setHasBetCurrentSlot] = useState(false);
  const [currentSlotBet, setCurrentSlotBet] = useState<{
    icon: string;
    amount: number;
  } | null>(null);

  useEffect(() => {
    loadCurrentSlot();
    const interval = setInterval(loadCurrentSlot, 30000); // Refresh every 30 seconds
    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    if (currentSlot) {
      updateTimeRemaining();
      const timer = setInterval(updateTimeRemaining, 1000);
      return () => clearInterval(timer);
    }
  }, [currentSlot]);

  const loadCurrentSlot = async () => {
    try {
      const slot = await predictionApi.getCurrentSlot().catch(() => null);
      setCurrentSlot(slot);
      if (slot) {
        setBetsByIcon(slot.betsByIcon || {});
        await loadMyCurrentSlotBet(slot.id);
      }
    } catch (error) {
      console.error("Failed to load current slot:", error);
    } finally {
      setSlotLoading(false);
    }
  };

  const loadMyCurrentSlotBet = async (slotId?: string) => {
    if (!slotId) {
      setHasBetCurrentSlot(false);
      setCurrentSlotBet(null);
      return;
    }
    try {
      const response = await betApi.getBets(slotId, 10, 0);
      const betsArray = Array.isArray(response) ? response : (response.data || []);
      const selfBet = betsArray.find((b: any) => b.slotId === slotId);
      setHasBetCurrentSlot(Boolean(selfBet));
      setCurrentSlotBet(
        selfBet ? { icon: selfBet.icon, amount: selfBet.amount } : null
      );
    } catch (error) {
      console.error("Failed to load current slot bet:", error);
    }
  };

  const updateTimeRemaining = () => {
    if (!currentSlot) return;
    const now = new Date();
    const end = new Date(currentSlot.endTime);
    const diff = end.getTime() - now.getTime();

    if (diff <= 0) {
      setTimeRemaining("Slot Closed");
      return;
    }

    const minutes = Math.floor(diff / 60000);
    const seconds = Math.floor((diff % 60000) / 1000);
    setTimeRemaining(`${minutes}:${seconds.toString().padStart(2, "0")}`);
  };

  const handlePlaceBet = async (e: React.FormEvent) => {
    e.preventDefault();
    setError("");
    setLoading(true);

    try {
      const amount = Number.parseFloat(betAmount);
      if (amount < 50) {
        setError("Minimum bet amount is ₹50");
        setLoading(false);
        return;
      }

      if (!selectedIcon) {
        setError("Please select an icon");
        setLoading(false);
        return;
      }

      if (!currentSlot) {
        setError("No active slot found");
        setLoading(false);
        return;
      }

      if (hasBetCurrentSlot) {
        setError("You have already placed a bet for this slot. Please wait for the result.");
        setLoading(false);
        return;
      }

      await betApi.placeBet(currentSlot.id, selectedIcon, amount);
      setBetAmount("50");
      setSelectedIcon("");

      const profile = (await authApi.getProfile()) as any;
      useAppStore.setState({ user: profile });

      await loadCurrentSlot();
    } catch (err: any) {
      setError(err.message || "Failed to place bet");
    } finally {
      setLoading(false);
    }
  };

  const quickActions = [
    {
      href: "/dashboard/wallet",
      label: "Wallet",
      icon: Wallet,
      description: "View balance and add money",
      color: "text-green-400",
    },
    {
      href: "/dashboard/transactions",
      label: "Transactions",
      icon: ArrowUpDown,
      description: "View transaction history",
      color: "text-blue-400",
    },
    {
      href: "/dashboard/withdrawals",
      label: "Withdrawals",
      icon: CreditCard,
      description: "Request withdrawals",
      color: "text-purple-400",
    },
  ];

  return (
    <div className="max-w-7xl mx-auto p-4 space-y-6">
      {/* Wallet Balance Card */}
      <Card className="border-slate-700 bg-slate-800">
        <CardHeader>
          <CardTitle className="flex items-center gap-2 text-white">
            <Wallet className="w-5 h-5" />
            Wallet Balance
          </CardTitle>
        </CardHeader>
        <CardContent>
          <div className="text-4xl font-bold text-green-400">
            ₹{user?.walletBalance.toFixed(2) || "0.00"}
          </div>
          <p className="text-slate-400 text-sm mt-2">Your current wallet balance</p>
        </CardContent>
      </Card>

      {/* Prediction Game Betting */}
      <Card className="border-slate-700 bg-slate-800">
        <CardHeader>
          <div className="flex justify-between items-center">
            <div>
              <CardTitle className="text-white flex items-center gap-2">
                <Gamepad2 className="w-5 h-5" />
                Prediction Game
              </CardTitle>
              <CardDescription className="text-slate-400">
                {currentSlot
                  ? `Slot #${currentSlot.slotNumber} • Time Remaining: ${timeRemaining}`
                  : "No active slot"}
              </CardDescription>
            </div>
            {currentSlot && (
              <div className="text-right">
                <p className="text-sm text-slate-400">Total Bets</p>
                <p className="text-xl font-bold text-blue-400">
                  {currentSlot.totalBets}
                </p>
              </div>
            )}
          </div>
        </CardHeader>
        <CardContent>
          {slotLoading ? (
            <div className="flex items-center justify-center py-12">
              <Spinner className="w-6 h-6 text-blue-400" />
              <p className="ml-3 text-slate-400">Loading slot...</p>
            </div>
          ) : !currentSlot ? (
            <div className="text-center py-8">
              <p className="text-slate-400">
                No active slot. Waiting for the next prediction slot to be created.
              </p>
              <Link href="/dashboard/prediction">
                <Button className="mt-4 bg-blue-600 hover:bg-blue-700 text-white">
                  Go to Prediction Game
                </Button>
              </Link>
            </div>
          ) : (
            <form onSubmit={handlePlaceBet} className="space-y-4">
              <div>
                <label className="text-sm font-medium text-slate-300 mb-2 block">
                  Choose Icon
                </label>
                <div className="grid grid-cols-4 md:grid-cols-6 gap-3">
                  {ICONS.map(({ id, name, Icon, color }) => {
                    const iconData = betsByIcon[id] || {
                      totalBets: 0,
                      totalAmount: 0,
                    };
                    const isSelected = selectedIcon === id;
                    const isMyBet = currentSlotBet?.icon === id;
                    return (
                      <button
                        key={id}
                        type="button"
                        onClick={() => setSelectedIcon(id)}
                        className={`p-3 rounded-lg border-2 transition-all ${
                          isSelected
                            ? "border-blue-500 bg-blue-500 bg-opacity-20"
                            : "border-slate-600 bg-slate-700 hover:border-slate-500"
                        }`}
                      >
                        <Icon className={`w-6 h-6 mx-auto mb-1 ${color}`} />
                        <p className="text-xs text-slate-300">{name}</p>
                        <p className="text-xs text-slate-400 mt-1">
                          {iconData.totalBets} bets • ₹{iconData.totalAmount.toFixed(0)}
                        </p>
                        {isMyBet && (
                          <p className="text-[10px] text-amber-300 mt-1 font-semibold">
                            Your bet
                          </p>
                        )}
                      </button>
                    );
                  })}
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-300">
                  Bet Amount (₹)
                </label>
                <Input
                  type="number"
                  min="50"
                  step="10"
                  placeholder="50"
                  value={betAmount}
                  onChange={(e) => setBetAmount(e.target.value)}
                  className="bg-slate-700 border-slate-600 text-white placeholder-slate-400"
                />
                {hasBetCurrentSlot && (
                  <p className="text-xs text-amber-400">
                    You have already placed a bet for this slot. Please wait for the result.
                  </p>
                )}
                {currentSlotBet && (
                  <p className="text-xs text-slate-300">
                    You placed{" "}
                    <span className="text-white font-semibold">
                      ₹{currentSlotBet.amount.toFixed(2)}
                    </span>{" "}
                    on{" "}
                    <span className="font-semibold text-blue-200">
                      {currentSlotBet.icon}
                    </span>
                    . Awaiting result.
                  </p>
                )}
              </div>

              {error && <p className="text-sm text-red-400">{error}</p>}

              <Button
                type="submit"
                disabled={
                  loading ||
                  !selectedIcon ||
                  Number.parseFloat(betAmount) < 50 ||
                  hasBetCurrentSlot
                }
                className="w-full bg-blue-600 hover:bg-blue-700 text-white disabled:opacity-50"
              >
                {loading ? (
                  <>
                    <Spinner className="w-4 h-4 mr-2" />
                    Placing Bet...
                  </>
                ) : (
                  "Place Bet"
                )}
              </Button>
            </form>
          )}
        </CardContent>
      </Card>

      {/* Quick Actions */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        {quickActions.map((action) => {
          const Icon = action.icon;
          return (
            <Link key={action.href} href={action.href}>
              <Card className="border-slate-700 bg-slate-800 hover:bg-slate-750 transition-colors cursor-pointer h-full">
                <CardContent className="p-6">
                  <div className="flex items-center gap-4">
                    <Icon className={`w-8 h-8 ${action.color}`} />
                    <div>
                      <h3 className="font-semibold text-white">{action.label}</h3>
                      <p className="text-sm text-slate-400">{action.description}</p>
                    </div>
                  </div>
                </CardContent>
              </Card>
            </Link>
          );
        })}
      </div>
    </div>
  );
}

